import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

/**
 * Runs the gnosis command-line workflow.
 */
export async function main() {
  const root = process.cwd();
  const formalLedgerPath = join(root, 'open-source/aeon/FORMAL_LEDGER.md');
  const theoremLedgerPath = join(root, 'open-source/gnosis/THEOREM_LEDGER.md');
  const ownershipPath = join(root, 'open-source/gnosis/scripts/ledger-mcp-ownership.ts');

  const formalLedger = readFileSync(formalLedgerPath, 'utf8');
  let theoremLedger = readFileSync(theoremLedgerPath, 'utf8');
  let ownershipContent = readFileSync(ownershipPath, 'utf8');

  // --- SURGICAL REPAIR STEP ---
  const corruptionMarker = '## Spiderweb Topology (2026-03-29)';
  const cutoffIndex = theoremLedger.indexOf(corruptionMarker);

  if (cutoffIndex !== -1) {
      theoremLedger = theoremLedger.substring(0, cutoffIndex).trimEnd();
      console.log('Sanitized corrupted unformatted sections from THEOREM_LEDGER.md.');
  }

  // Parse FORMAL_LEDGER.md
  const sections: { title: string; subtables: { subtitle: string; theorems: { name: string; id: string; text: string }[] }[] }[] = [];

  let currentSection: any = null;
  let currentSubtitle: any = null;

  const lines = formalLedger.split(/\r?\n/);

  for (let line of lines) {
    if (line.startsWith('## ')) {
      currentSection = { title: line.replace('## ', '').trim(), subtables: [] };
      sections.push(currentSection);
      currentSubtitle = null;
    } else if (line.startsWith('### ') && currentSection) {
      currentSubtitle = { subtitle: line.replace('### ', '').trim(), theorems: [] };
      currentSection.subtables.push(currentSubtitle);
    } else if (line.startsWith('- **') && currentSection) {
      const match = line.match(/^- \*\*([^*]+)\*\*(.*?): (.*)/);
      if (match && currentSubtitle) {
        let name = match[1].trim();
        let text = match[3].trim();
        let idMatch = match[2].match(/\(([^)]+)\)/);
        let id = idMatch ? idMatch[1].trim() : `THM-${name.toUpperCase().replace(/[^A-Z0-9]+/g, '-').replace(/(^-|-$)/g, '')}`;
        if (!id.startsWith('THM-') && !id.startsWith('PRED-') && !id.startsWith('COR-')) {
          id = `THM-${id.toUpperCase().replace(/[^A-Z0-9]+/g, '-').replace(/(^-|-$)/g, '')}`;
        }
        currentSubtitle.theorems.push({ name, id, text });
      } else {
          const fallbackMatch = line.match(/^- \*\*([^*]+)\*\*\s*(.*)/);
          if (fallbackMatch && currentSubtitle) {
              let name = fallbackMatch[1].trim();
              let text = fallbackMatch[2].trim();
              let id = `THM-${name.toUpperCase().replace(/[^A-Z0-9]+/g, '-').replace(/(^-|-$)/g, '')}`;
              currentSubtitle.theorems.push({ name, id, text });
          }
      }
    }
  }

  let newlyAddedCount = 0;
  let newlyAddedRows = 0;

  for (const section of sections) {
    if (theoremLedger.includes(`## ${section.title}`) || theoremLedger.includes(`### ${section.title}`)) {
      continue;
    }
    
    if (section.subtables.every(s => s.theorems.length === 0)) {
        continue;
    }

    let tableMarkdown = `\n\n## ${section.title}\n\n*Auto-formalized cross-pollination*\n\n`;

    for (const sub of section.subtables) {
      if (sub.theorems.length === 0) continue;
      
      tableMarkdown += `**${sub.subtitle}**\n\n`;
      tableMarkdown += `| Theorem ID | Formal Statement | Topology Family | Proof Status | Confidence Layer |\n`;
      tableMarkdown += `|------------|-----------------|-----------------|--------------|------------------|\n`;

      for (const thm of sub.theorems) {
        tableMarkdown += `| \`${thm.id}\` | ${thm.text} | ${sub.subtitle} | Lean generic proof pending | Conceptual |\n`;
        newlyAddedRows++;
      }
      tableMarkdown += `\n`;
    }

    theoremLedger += tableMarkdown;
    newlyAddedCount++;

    const mcpServer = section.title.toLowerCase().includes('fail') ? 'failure-mcp' : 'topology-mcp';
    if (!ownershipContent.includes(section.title)) {
        const injectionString = `  {
    section: '${section.title}',
    server: '${mcpServer}',
  },`;
        ownershipContent = ownershipContent.replace(/\] as const;/m, `${injectionString}\n] as const;`);
    }
  }

  console.log(`Newly formulated sections: ${newlyAddedCount}`);
  console.log(`Newly formulated theorems: ${newlyAddedRows}`);

  if (newlyAddedCount > 0 || newlyAddedRows > 0) {
    const coveragePath = join(root, 'open-source/gnosis/scripts/generate-ledger-mcp-coverage.ts');
    let coverageContent = readFileSync(coveragePath, 'utf8');
    
    coverageContent = coverageContent.replace(
        /export const EXPECTED_CANONICAL_LEDGER_ROW_COUNT = (\d+);/,
        (_, count) => `export const EXPECTED_CANONICAL_LEDGER_ROW_COUNT = ${parseInt(count) + newlyAddedRows};`
    );
    coverageContent = coverageContent.replace(
        /export const EXPECTED_CANONICAL_LEDGER_SECTION_COUNT = (\d+);/,
        (_, count) => `export const EXPECTED_CANONICAL_LEDGER_SECTION_COUNT = ${parseInt(count) + newlyAddedCount};`
    );
    
    writeFileSync(coveragePath, coverageContent, 'utf8');
  }

  writeFileSync(theoremLedgerPath, theoremLedger, 'utf8');
  writeFileSync(ownershipPath, ownershipContent, 'utf8');
  console.log('Appended to THEOREM_LEDGER.md, updated ownership, and updated coverage counts.');
}
